-- Delliza clean code / safe order update - 2026-07-18
-- این فایل فقط منو، دسته‌بندی و تنظیمات را آپدیت می‌کند.
-- ردیف orders اصلاً دستکاری نمی‌شود؛ پس سفارش‌های قبلی نمی‌پرند.

create table if not exists public.app_data (
  key text primary key,
  value jsonb not null,
  updated_at timestamptz not null default now()
);

-- بکاپ اختیاری از سفارش‌ها قبل از آپدیت؛ فقط برای اطمینان.
create table if not exists public.app_data_orders_backup (
  id bigserial primary key,
  backed_up_at timestamptz not null default now(),
  value jsonb not null
);

insert into public.app_data_orders_backup (value)
select value
from public.app_data
where key = 'orders'
  and value is not null;

